function ModelDivineWeapon:OnDivineWeaponDecomposeReq(items)
	local pb = LProtoHelper.CreateProto(LProtoIds.DivineWeaponDecomposeReq)
	for i, item in ipairs(items) do
		local ref = gModelItem:GetRefByRefId(item.refId)
		pb.items:add()
		pb.items[i].refId = item.refId
        pb.items[i].num = item.count
        pb.items[i].type = ref and ref.type or 0
	end
	SendMessage(pb,LProtoIds.DivineWeaponDecomposeReq)
end
