function ModelDivineWeapon:OnUpdateDivineWeapon(pb)
	---@type StructDivineWeapon
	local info = self.divineWeaponMap[pb.refId]
	if not info then info = StructDivineWeapon:New() end
	info:CreateByPb(pb)
	self.divineWeaponMap[pb.refId] = info
end

function ModelDivineWeapon:OnDivineWeaponInfoResp(pb)
	self.resonanceLvRefId = pb.resonanceLevel
	self.expNums = pb.expNums
	for _, obj in ipairs(pb.objs) do
		self:OnUpdateDivineWeapon(obj)
	end
	for _, resonance in ipairs(pb.resonanceObjs) do
		self.resonanceMap[resonance.refId] = resonance.levelRefId
	end
	for _, relation in ipairs(pb.relationObjs) do
		self.divineWeaponBook[relation.refId] = relation.lvRefId
	end
	self.freeDropNum = pb.freeDropNum
	self.diamondDropNum = pb.diamondDropNum
	self.wishWeaponId = pb.wishWeaponId
	self.dropProgress = pb.dropProgress
	for _, rwdIndx in ipairs(pb.progressRewardIdxs) do
		self.progressRewardIdxs[rwdIndx] = rwdIndx
	end
	self.attrs = pb.attrs
	self.divineWeaponAttr = pb.DivineWeaponAttr
	self.relationAttr = pb.relationAttr
	self.isCanWish = pb.isCanWish
	self.resonanceRewards = {}
	for _, rwd in ipairs(pb.resonanceRewards) do
		table.insert(self.resonanceRewards,rwd)
	end
	FireEvent(EventNames.DIVINE_WEAPON_UPDATE,1)
	if self.wishWeaponId and self.wishWeaponId>0 then
		FireEvent(EventNames.DIVINE_WEAPON_CALL_WISH)
	end
end
function ModelDivineWeapon:OnDivineWeaponUpStarResp(pb)
	local info = self.divineWeaponMap[pb.obj.refId]
	local preStarRefId = info and info.starRefId
	self:OnUpdateDivineWeapon(pb.obj)
	GF.OpenWnd("UIDivineActiveSucces",{refId = pb.obj.refId,isActive = not info,preStarRefId = preStarRefId })
	FireEvent(EventNames.DIVINE_WEAPON_UPDATE,{isActive = not info})
end

function ModelDivineWeapon:OnDivineWeaponUpLevelResp(pb)
	self:OnUpdateDivineWeapon(pb.obj)
