end

function ModelDivineWeapon:OnDivineWeaponResonanceUpLvResp(pb)
	local lvRefId = self.resonanceMap[pb.obj.refId]
	if pb.obj.refId then 
		self.resonanceMap[pb.obj.refId] = pb.obj.levelRefId 
