function ModelDivineWeapon:OnDivineWeaponObjsUpdateResp(pb)
	--圣武数据
	for _, obj in ipairs(pb.objs) do
		self:OnUpdateDivineWeapon(obj)
	end
	local oldResonanceRefId = self.resonanceLvRefId
    --共鸣科技等级
    self.resonanceLvRefId = pb.resonanceLevel;
    --累计共鸣经验值
    self.expNums = pb.expNums;
	FireEvent(EventNames.DIVINE_WEAPON_TECHNOLOGY)
	if oldResonanceRefId>0 and oldResonanceRefId ~= self.resonanceLvRefId then
		GF.OpenWnd("UIDivineResonanceUpPop",{oldRefId = oldResonanceRefId})
	end
end
