-- 获取圣武碎片分解获得的物品
function ModelDivineWeapon:GetDivineResolveItemList(itemList)
    if not self._itemResolveRef then
        local map = {}
        for k, v in pairs(GameTable.DivineWeaponRef) do
            map[v.item] = {}
            map[v.item].ref = v

            local list = {}
            list[1] = LUtil.GetRefItemData(v.itemSell)
            map[v.item].itemSell = list
        end
        self._itemResolveRef = map
    end

    local map = {}
    for _, v in ipairs(itemList) do
        local list = self._itemResolveRef[v.refId] and self._itemResolveRef[v.refId].itemSell
        for _, tab in ipairs(list or {}) do
            if not map[tab.refId] then
                map[tab.refId] = { refId = tab.refId, count = v.count * tab.count, type = tab.type }
            else
                map[tab.refId].count = map[tab.refId].count + v.count * tab.count
            end
        end
    end

    local list = {}
    for k, v in pairs(map) do
        v.itemId = v.refId
        v.itemNum = v.count
        v.itype = v.type
        v.itemType = v.type
        table.insert(list, v)
    end

    return list
end
-- 通过物品id判断相应的圣武是否已满星
function ModelDivineWeapon:GetDivineStarByItemId(itemRefId)
    if not self._itemResolveRef then
        local map = {}
        for k, v in pairs(GameTable.DivineWeaponRef) do
            map[v.item].ref = v
            map[v.item].itemSell = LUtil.GetRefItemData(v.itemSell)
        end
        self._itemResolveRef = map
    end

    if not self._itemResolveRef[itemRefId] then
        return nil
    end

    local refId = self._itemResolveRef[itemRefId].ref.refId
    local star = self:GetCurStar(refId)
    return star, refId
end

-- 获取当前激活技能
function ModelDivineWeapon:GetSkillId(refId)
	local divineInfo = self.divineWeaponMap[refId]
	local starRef = nil
	if divineInfo and divineInfo.starRefId then
		starRef = self:GetCurStarRef(refId)
	else--沒激活-返回最高技能
		local refs = self:GetDiviWeaponStarByRefId(refId)
		starRef = refs[#refs]
	end
    return starRef and starRef.skillId
end
--聖武配置
function ModelDivineWeapon:GetDivineWeaponRef(refId)
   if refId then return GameTable.DivineWeaponRef[refId] end
   if not self.divineWeaponRedByQuality then 
		self.divineWeaponRedByQuality = {}
		local refs = GameTable.DivineWeaponRef
		for _, value in pairs(refs) do
			if not self.divineWeaponRedByQuality[value.quality] then self.divineWeaponRedByQuality[value.quality] = {} end 
			table.insert(self.divineWeaponRedByQuality[value.quality],value)
		end
		for _, list in pairs(self.divineWeaponRedByQuality) do
			table.sort(list,function(a, b) return a.refId>b.refId end)
		end
	end
	return self.divineWeaponRedByQuality
end
--通過聖武id拿等級配置
function ModelDivineWeapon:GetDiviWeaponLvRefByRefId(refId)
	if not self.diviWeaponLvRefByQuality then 
		local refs = GameTable.DivineWeaponLevelRef
		self.diviWeaponLvRefByQuality = {}
		self.divineWeaponUpLvLimit = {}
		for _, value in pairs(refs) do
			if not self.diviWeaponLvRefByQuality[value.quality] then 
				self.diviWeaponLvRefByQuality[value.quality] = {}
			end
			table.insert(self.diviWeaponLvRefByQuality[value.quality],value)
			local lv = self.divineWeaponUpLvLimit[value.star] or 0
			if value.level>lv then 
				self.divineWeaponUpLvLimit[value.star] = value.level
			end
		end
		for _, list in pairs(self.diviWeaponLvRefByQuality) do
			table.sort(list,function(a, b) return a.level<b.level end)
		end
	end
	if not refId then return end
	local swRef = self:GetDivineWeaponRef(refId)
	local quality = swRef.quality
	return self.diviWeaponLvRefByQuality[quality]
end
function ModelDivineWeapon:GetStarUpLvMaxLimit(star)
	if not self.divineWeaponUpLvLimit then 
		self:GetDiviWeaponLvRefByRefId()
	end
	return self.divineWeaponUpLvLimit[star]
end
