--聖武星級配置
function ModelDivineWeapon:GetCurStarRef(refId)
	local divineInfo = self.divineWeaponMap[refId]
	if divineInfo and divineInfo.starRefId then 
		return GameTable.DivineWeaponStarRef[divineInfo.starRefId]
	end
end
--聖武等級配置
function ModelDivineWeapon:GetCurLevelRef(refId)
	if not refId then return end
	local divineInfo = self.divineWeaponMap[refId]
	if divineInfo and divineInfo.levelRefId then 
		return GameTable.DivineWeaponLevelRef[divineInfo.levelRefId]
	end
end
--聖武等級配置
function ModelDivineWeapon:GetLevelRef(refId,lv)
	if not refId then return end
	local lvRefs = self:GetDiviWeaponLvRefByRefId(refId)
	local lvRef = lvRefs[lv]
	local tempLv = lv
	while(lvRef and lvRef.level<lv) do
		tempLv = tempLv+1
		lvRef = lvRefs[tempLv]
	end
	return lvRef
end

--共鸣等级配置
function ModelDivineWeapon:GetResonanceLvRef()
	if not self.divineResonanceLvRef then
		self.divineResonanceIndxCondi = {}
		self.divineResonanceLvRef = {}
		local refs = GameTable.DivineWeaponResonanceRef
		for key, value in pairs(refs) do
			table.insert(self.divineResonanceLvRef,value)
			local curRef = self.divineResonanceIndxCondi[value.slotNum]
			if not curRef or curRef.level> value.level then self.divineResonanceIndxCondi[value.slotNum] = value end
		end
		table.sort(self.divineResonanceLvRef,function(a, b) return a.level<b.level end)
	end
	return self.divineResonanceLvRef,self.divineResonanceIndxCondi
end
-- 获取召唤许愿概率
function ModelDivineWeapon:GetSummonWishRate()
    return GameTable.DivineWeaponConfigRef.specialRate * 0.01
end

-- 获取召唤奖励池配置
function ModelDivineWeapon:GetSummonItemPoolRef()
    if not self._summonItemPoolRef then
        local list = {}
        for k, v in pairs(GameTable.DivineWeaponSummonRef) do
            if v.type == 10 then
                table.insert(list, v)
            end
        end

        table.sort(list, function(a, b)
            return a.sort > b.sort
        end)

        self._summonItemPoolRef = list
    end
    return self._summonItemPoolRef
end

--聖武升星消耗
function ModelDivineWeapon:GetUpStarCost(refId)
	local starCfg = self:GetCurStarRef(refId)
	if starCfg then 
		local nextStarCfg = GameTable.DivineWeaponStarRef[starCfg.rankNext]----激活-返回一下消耗
		return nextStarCfg and LxDataHelper.ParseItem_4(nextStarCfg.upNeed)
	else
		local starCfgs = self:GetDiviWeaponStarByRefId(refId)
		starCfg = starCfgs[1]
		return LxDataHelper.ParseItem_4(starCfg.upNeed)
	end
end

--聖武升級消耗
function ModelDivineWeapon:GetLevelCost(refId)
	local levelCfgt = self:GetCurLevelRef(refId)
	if levelCfgt then 
		return levelCfgt.nextLevel>0 and LxDataHelper.ParseItem_4(levelCfgt.upNeed)
	else
		local lvRef = self:GetDiviWeaponLvRefByRefId(refId)
		return LxDataHelper.ParseItem_4(lvRef[1].upNeed)
	end
end


--聖武升級屬性
function ModelDivineWeapon:GetLevelAttr(refId)
	local curLvRef = nil
	curLvRef = self:GetCurLevelRef(refId)
	local nexLvRef 
	if curLvRef and curLvRef.nextLevel>0 then nexLvRef = self:GetLevelRef(refId,curLvRef.level+1) end
	local curLvAttr = curLvRef and LxDataHelper.ParseAttrList(curLvRef.attr)
	local nexLvAttr = nexLvRef and LxDataHelper.ParseAttrList(nexLvRef.attr)
	return  curLvAttr,nexLvAttr
end
--生物升星屬性
function ModelDivineWeapon:GetStarAttr(refId)
	local starRef = self:GetCurStarRef(refId)
	local nextStarCfg = nil
	if starRef and starRef.rankNext>0 then nextStarCfg = GameTable.DivineWeaponStarRef[starRef.rankNext] end
	local curAttr = starRef and LxDataHelper.ParseAttrList(starRef.attr)
	local nexAttr = nextStarCfg and LxDataHelper.ParseAttrList(nextStarCfg.attr)
	return curAttr,nexAttr
end

--最大星级
function ModelDivineWeapon:GetMaxStar(refId)
	local starRefs = self:GetDiviWeaponStarByRefId(refId)
	local starCfg = starRefs[#starRefs]
    if starCfg then
		return starCfg.rankNow
    end
	return 0
end
--当前星级
function ModelDivineWeapon:GetCurStar(refId)
	local info = self.divineWeaponMap[refId]
	return info and info.star
end

--科技屬性
function ModelDivineWeapon:GetResonanceAttr(refId)
	local lvRefs = GameTable.DivineWeaponResonanceLevelRef
	if refId then 
		local lvRefId = self.resonanceMap[refId]
		if not lvRefId then return end
		local lvRef = lvRefs[lvRefId]
		return lvRef and LxDataHelper.ParseAttrList(lvRef.attr)
	else
		local indx = 0
		local attrStr = ""
		for id, lvRefId in pairs(self.resonanceMap) do
			indx = indx+1
			local lvCfg = lvRefs[lvRefId]
			if indx==1 then 
				if lvCfg then attrStr = lvCfg.attr end
			else
				if lvCfg then attrStr = attrStr..","..lvCfg.attr end
			end
		end
		local totalAttrMap = LUtil.ConvertCommonAttrStrToMap(attrStr)
		local attrs = LUtil.MapAttrToListAttr(totalAttrMap)
		return attrs
	end
end
--等级附加属性加成
function ModelDivineWeapon:GetDivineLevelAttrAdd(refId)
	local info = self.divineWeaponMap[refId]
	if not info then return 0 end
	local list = gModelDivineWeapon:GetDiviWeaponLvAddRefByRefId(refId) or {}
	local add = 0
	for _, value in ipairs(list) do
		if value.level <= info.level then 
			add = add + value.divineWeaponIdAdd 
		else
			break
		end
	end
	return add
end

function ModelDivineWeapon:GetSummonDetail()
    local idMap = {}
    local tab = string.split(GameTable.DivineWeaponConfigRef.jackpotRate, ";")
    for k, v in ipairs(tab) do
        local data = string.split(v, "=")
        idMap[tonumber(data[1])] = true
    end

    local list = {}
    for _, ref in pairs(GameTable.DivineWeaponSummonRef) do
        if idMap[ref.type] and ref.probabilityShow>0 then
            table.insert(list, ref)
        end
    end

    table.sort(list, function(a, b)
        if a.sort ~= b.sort then
            return a.sort < b.sort
        end
        return a.refId < b.refId
    end)
    return list
end

function ModelDivineWeapon:IsSkillOpenByPos(indx,id)
	local _,indxCondiRef = self:GetResonanceLvRef()
	local ref = indxCondiRef[indx]
	local isOpen = false
	if  self.resonanceLvRefId and self.resonanceLvRefId >0 then 
		local resonanceRef = GameTable.DivineWeaponResonanceRef[self.resonanceLvRefId]
		isOpen = resonanceRef.level>=ref.level
	end
	return isOpen,string.replace(ccClientText(id or 46149,ref.level))
end
--圣武升星红点
function ModelDivineWeapon:DivineWeaponStarRedById(refId)
	local cost = self:GetUpStarCost(refId)
	if not cost then return false end
	local curNum = gModelItem:GetNumByRefId(cost.itemId)
	return curNum>=cost.itemNum
end 
--圣武升级红点
function ModelDivineWeapon:DivineWeaponUpRedById(refId)
	if not self.divineWeaponMap[refId] then return end
	local cost = self:GetLevelCost(refId)
	if not cost then return false end
	local curMaxLimit = self:GetStarUpLvMaxLimit(self.divineWeaponMap[refId].star)
	if curMaxLimit <= self.divineWeaponMap[refId].level then 
		local starRef= GameTable.DivineWeaponStarRef[self.divineWeaponMap[refId].starRefId]
		local nexStarRef = GameTable.DivineWeaponStarRef[starRef.rankNext]
		return false,nexStarRef.rankNow
	end
	local curNum = gModelItem:GetNumByRefId(cost.itemId)
	return curNum>=cost.itemNum
end 
-- 组合图鉴激活红点
function ModelDivineWeapon:DivineWeaponBookRed(group)
	if self.divineWeaponBook[group] then return false end
	local refs = self:GetDiviWeaponBookRef(group)
	local ref = refs[1]
	local enough = true
	local refIds = string.split(ref.divineWeaponId,"|")
	for i = 1, #refIds do
		if refIds[i] then 
			local info = self:GetDivineWeaponByRefId(tonumber(refIds[i]))
			if not info then enough = false end
		end
	end
	return enough
end
--科技点红点
function ModelDivineWeapon:DivineWeaponTechnologyRed(refId)
	local lvCfg = self:GetDivineCurResonanceRef(refId)
	local cfgs = gModelDivineWeapon:GetDiviWeaponResonanceLvRef(refId)
	local cost 
	if not lvCfg then
		local cfg = gModelDivineWeapon:GetDiviWeaponResonanceLvRef(refId)
		lvCfg = cfg[1]
		cost = LxDataHelper.ParseItem_4(lvCfg.upNeed)
	else
		local nexlvCfg = cfgs[lvCfg.level+1]
		cost = nexlvCfg and LxDataHelper.ParseItem_4(nexlvCfg.upNeed)
	end
	local isOk = self:GetForeCondition(refId,true)
	if not cost or not isOk then return false end
	local curNum = gModelItem:GetNumByRefId(cost.itemId)
	return curNum>= cost.itemNum
end
-- --科技点可领取
-- function ModelDivineWeapon:DivineWeaponRewardRed()
-- 	return self.resonanceRewards and #self.resonanceRewards>0
-- end 

function ModelDivineWeapon:GetForeCondition(refId,oneBreak)
	local cfg = GameTable.DivineWeaponTechnologyRef[refId]
	local ids = string.split(cfg.nextSktill,"|")
	if #ids==0 then return true end
	
	local conditions = string.split(cfg.precondition,"|")
	local conditionMap = {}
	for _, value in ipairs(conditions) do
		local condi = string.split(value,"=")
		conditionMap[tonumber(condi[1])] = tonumber(condi[2])
	end
	local totalLv = 0
	for _, id in ipairs(ids) do
		totalLv = totalLv+self:GetDivineCurResonanceLv(tonumber(id))
	end
	local resonanceRef = GameTable.DivineWeaponResonanceRef[self.resonanceLvRefId]
	local conditionState = {}
	local result = true
	for type, vlaue in pairs(conditionMap) do
		local isOk = true
		if type==2 then
			if vlaue > totalLv then 
				isOk = false
				-- break
			end 
		elseif type==1 then
			if vlaue > (resonanceRef and resonanceRef.level or 0) then 
				isOk = false
				-- break
			end
		else
			for _, id in ipairs(ids) do
				local lv = self:GetDivineCurResonanceLv(tonumber(id))
				if vlaue>lv then 
					-- return false,conditionMap
					isOk = false
					break
				end
			end
		end
		if result and not isOk then result = isOk end
		conditionState[type] = isOk
		if not isOk and oneBreak then break end
	end
	return result,conditionMap,conditionState
end

function ModelDivineWeapon:GetActivateStarRefId()
	local list = {}
	for _, value in pairs(self.divineWeaponMap) do
		if value.starRefId then 
			local starRef = GameTable.DivineWeaponStarRef[value.starRefId]
			if starRef and starRef.skillId>0 then  table.insert(list,starRef) end
		end
	end
	return list
end
-- 获取当前圣武已被其它圣武附魂的圣武id, 0表示没有被引用
function ModelDivineWeapon:GetMainAttachRefId(refId)
    for k, v in pairs(self.divineWeaponMap) do
        if v.linkRefId == refId then
            return v.refId
        end
    end
    return 0
end


-- 返回true, 表示龙魂已上阵 (检查所有阵型）
function ModelDivineWeapon:HadUsedCheckAllFormations(refId)
    for k, v in pairs(self.divineWeaponMap) do
        if v.refId == refId then
            return v.isDeploy == 1
        end
    end

    return false
end

function ModelDivineWeapon:GetDivineIdBySkillId(skillId)
	if not skillId or skillId < 1 then return end
	if not self._skillId2DivineIdMap then
		self._skillId2DivineIdMap = {}
	end
	local divineId = self._skillId2DivineIdMap[skillId]
	if not divineId then
		for k,v in pairs(GameTable.DivineWeaponStarRef) do
			if v.skillId == skillId then
				divineId = v.type
				break
			end
		end
		self._skillId2DivineIdMap[skillId] = divineId
	end
	return divineId
end

-- 获取圣武一键上阵
function ModelDivineWeapon:GetOneKeyFormationRefIdList(excludeMap)
    local list = {}
    for k, v in pairs(self.divineWeaponMap) do
        local ref = GameTable.DivineWeaponRef[v.refId]
        if ref.effetcType == 1 and not excludeMap[v.starRefId] and self:GetMainAttachRefId(ref.refId) == 0 then
            table.insert(list, { ref = ref, upRef = GameTable.DivineWeaponStarRef[v.starRefId] })
        end
    end

    table.sort(list, function(a, b)
        if a.ref.quality ~= b.ref.quality then
            return a.ref.quality > b.ref.quality
        end
        if a.upRef.rankNow ~= b.upRef.rankNow then
            return a.upRef.rankNow > b.upRef.rankNow
        end
        return a.ref.sort > b.ref.sort
    end)

    local newList = {}
    for i = 1, 4 do
        if list[#list - i + 1] and self:IsSkillOpenByPos(i) then
            newList[i] = list[i].upRef.refId
        end
    end
    return newList
end

---@return V_DivineWeaponRef
function ModelDivineWeapon:GetDivineRefBySkillId(skillId)
	local divineId = self:GetDivineIdBySkillId(skillId)
	if not divineId then return end
	return GameTable.DivineWeaponRef[divineId]
end


function ModelDivineWeapon:GetStarNumBySkillId(skillId)
	if not self._skillId2StarNumMap then
		self._skillId2StarNumMap = {}
	end
	local starNum = self._skillId2StarNumMap[skillId]
	if not starNum then
		for k,v in pairs(GameTable.DivineWeaponStarRef) do
			if v.skillId == skillId then
				starNum = v.rankNow
				break
			end
		end
		self._skillId2StarNumMap[skillId] = starNum
	end
	return starNum
end

return ModelDivineWeapon